<?php
namespace App\Modules\Hr\Compensation\Actions;use App\Modules\Hr\Compensation\Models\HrSalaryBand;use App\Modules\Hr\Core\Services\HrAuditService;use App\Modules\Hr\Core\Services\TenantContext;
class ManageSalaryBandAction{public function __construct(private HrAuditService $audit){}public function execute(array $data):HrSalaryBand{abort_unless(auth()->user()?->hasHrPermission('hr.salary.manage'),403);$min=(float)($data['minimum']??0);$mid=(float)($data['midpoint']??0);$max=(float)($data['maximum']??0);abort_if(blank($data['code']??null)||blank($data['name']??null)||$min<=0||$min>$mid||$mid>$max,422,'Ücret bandı sınırları geçersiz.');$band=HrSalaryBand::create(['legal_entity_id'=>app(TenantContext::class)->getId(),'code'=>strtoupper(trim($data['code'])),'name'=>trim($data['name']),'position_id'=>$data['position_id']??null,'minimum_salary_encrypted'=>(string)$min,'midpoint_salary_encrypted'=>(string)$mid,'maximum_salary_encrypted'=>(string)$max,'currency'=>$data['currency']??'TRY','effective_from'=>$data['effective_from'],'is_active'=>true]);$this->audit->log('salary_band_created',$band,null,['amounts'=>'[MASKED]']);return $band;}}
